import{_ as t,o as a,c as n,ag as i}from"./chunks/framework.BYehg5q7.js";const c=JSON.parse('{"title":"Supplements & Medications","description":"","frontmatter":{},"headers":[],"relativePath":"guide/supplements.md","filePath":"guide/supplements.md","lastUpdated":1771855656000}'),o={name:"guide/supplements.md"};function s(r,e,l,d,p,h){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="supplements-medications" tabindex="-1">Supplements &amp; Medications <a class="header-anchor" href="#supplements-medications" aria-label="Permalink to &quot;Supplements &amp; Medications&quot;">​</a></h1><p>Tracking your supplements and medications alongside your lab results lets you see what you were taking at the time of each blood draw — making it much easier to attribute changes to specific interventions.</p><h2 id="adding-supplements" tabindex="-1">Adding Supplements <a class="header-anchor" href="#adding-supplements" aria-label="Permalink to &quot;Adding Supplements&quot;">​</a></h2><p>Scroll to the <strong>Supplements</strong> section on the dashboard and click <strong>Add Supplement</strong> (or the add button). For each entry you can record:</p><ul><li><strong>Name</strong> — the supplement or medication name</li><li><strong>Dose</strong> — amount per dose</li><li><strong>Frequency</strong> — how often you take it</li><li><strong>Start date</strong> — when you began</li><li><strong>End date</strong> — when you stopped (leave blank if ongoing)</li><li><strong>Notes</strong> — anything worth remembering (brand, why you started, side effects, etc.)</li></ul><h2 id="timeline-bars-on-charts" tabindex="-1">Timeline Bars on Charts <a class="header-anchor" href="#timeline-bars-on-charts" aria-label="Permalink to &quot;Timeline Bars on Charts&quot;">​</a></h2><p>Once you have supplements recorded, open the <strong>Layers</strong> dropdown in the chart area and enable <strong>Supplements</strong> to overlay timeline bars at the bottom of each chart. Each bar spans the date range when you were taking that supplement.</p><p>This makes it easy to answer questions like:</p><ul><li>Did my ferritin improve after I started iron supplementation?</li><li>Did my LDL change when I added fish oil?</li><li>Was I on that medication during the period when my liver enzymes were elevated?</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The supplement overlay is especially useful when you have multiple lab dates. Enable it alongside the chart&#39;s reference range band to see at a glance whether a supplement coincided with an improvement or a new issue.</p></div><h2 id="editing-and-deleting" tabindex="-1">Editing and Deleting <a class="header-anchor" href="#editing-and-deleting" aria-label="Permalink to &quot;Editing and Deleting&quot;">​</a></h2><p>Click any supplement in the list to edit it. Use the delete button (trash icon) to remove it. Changes take effect immediately.</p><h2 id="in-ai-chat" tabindex="-1">In AI Chat <a class="header-anchor" href="#in-ai-chat" aria-label="Permalink to &quot;In AI Chat&quot;">​</a></h2><p>Your supplement list is included in the context sent to the AI when you chat. The AI can reference what you were taking during each blood draw and factor that into its analysis.</p><h2 id="export-and-import" tabindex="-1">Export and Import <a class="header-anchor" href="#export-and-import" aria-label="Permalink to &quot;Export and Import&quot;">​</a></h2><p>Supplements are included in your JSON export file and restored on import.</p>',16)])])}const m=t(o,[["render",s]]);export{c as __pageData,m as default};
